}

private enum WiseScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("accueil") || t.contains("home") || t.contains("activity"):
            WiseHomeScreen()
        case let t where t.contains("card") || t.contains("invest") || t.contains("crypto") || t.contains("market") || t.contains("trade") || t.contains("financ"):
            WiseCardsScreen()
        case let t where t.contains("recipient") || t.contains("plus"):
            WiseMoreScreen()
        default:
            WiseGenericListScreen(title: tab)
        }
    }
}
